external_knowledge:
- 'well-known artists' refers to artists with higher popularity; 
- 'popular tracks' refers to tracks with a popularity score higher than the average; 
- 'large following' refers to users with more than 100 followers.

sql:
SELECT track_id, AVG(energy) AS avg_energy, danceability, popularity
FROM audio_features
GROUP BY track_id, danceability, popularity;

SELECT SUM(play_count) AS total_plays
FROM listening_history
WHERE user_id = 1;

SELECT play_count
FROM listening_history
WHERE user_id = 1 AND track_id = '1';

SELECT track_id
FROM listening_history
WHERE play_count = (SELECT MAX(play_count) FROM listening_history);
